import { strict as assert } from "node:assert";
import { readFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { describe, it } from "node:test";
import { fileURLToPath } from "node:url";
import {
  EXPLICIT_REVIEW_KEYWORDS,
  IMPLEMENT_KEYWORDS,
  DEBUG_KEYWORDS,
  PLAN_KEYWORDS,
  TOOL_KEYWORDS,
  ORCHESTRATION_KEYWORDS,
  MODEL_CANDIDATES,
  MODEL_FAMILIES,
  getModelFamily,
  normalizePrompt,
  matchesPattern,
  includesAny,
  isExplicitReviewRequest,
  isToolHeavy,
  isComplexOrchestration,
  getComplexity,
  classifyPrompt,
  getTierCandidates,
  dedupeCandidates,
  isSameModelFamily,
  orderCandidates,
  buildAdditionalContext,
} from "../.github/extensions/model-router/policy.mjs";

const __dirname = dirname(fileURLToPath(import.meta.url));
const MATRIX_CONTENT = readFileSync(
  join(__dirname, "../.github/skills/model-router/references/routing-matrix.md"),
  "utf8",
);

  // Verify diversity IS silently achieved when review uses a different family
  it("does not surface fallback note when review uses a distinct family", () => {
    const decision = { kind: "review", complexity: 1, selectedModelId: "gpt-5.4", reasoningEffort: "high" };
    const ctx = buildAdditionalContext(decision, "gpt-5.4", "claude-sonnet-4.6");
    assert.ok(!ctx.includes("fell back"), `unexpected fallback note; got: ${ctx}`);
  });
});

// ---------------------------------------------------------------------------
// Tier and reasoning-effort regression
// Pin specific models to their expected tier and reasoningEffort so that
// accidental moves or effort changes are caught immediately.
// ---------------------------------------------------------------------------
describe("tier and reasoning-effort regression", () => {
  it("claude-haiku-4.5 is in economy with no reasoning effort", () => {
    const entry = MODEL_CANDIDATES.economy.find((m) => m.id === "claude-haiku-4.5");
    assert.ok(entry, "claude-haiku-4.5 missing from economy tier");
    assert.equal(entry.reasoningEffort, null);
  });

  it("gpt-5-mini is in economy with low reasoning effort", () => {
    const entry = MODEL_CANDIDATES.economy.find((m) => m.id === "gpt-5-mini");
    assert.ok(entry, "gpt-5-mini missing from economy tier");
    assert.equal(entry.reasoningEffort, "low");
  });

  it("claude-sonnet-4.6 is in builder with medium reasoning effort", () => {
    const entry = MODEL_CANDIDATES.builder.find((m) => m.id === "claude-sonnet-4.6");
    assert.ok(entry, "claude-sonnet-4.6 missing from builder tier");
    assert.equal(entry.reasoningEffort, "medium");
  });

  it("gpt-5.1 is in builder with medium reasoning effort", () => {
    const entry = MODEL_CANDIDATES.builder.find((m) => m.id === "gpt-5.1");
    assert.ok(entry, "gpt-5.1 missing from builder tier");
    assert.equal(entry.reasoningEffort, "medium");
  });

  it("claude-sonnet-4.6 is in reasoning with high reasoning effort", () => {
    const entry = MODEL_CANDIDATES.reasoning.find((m) => m.id === "claude-sonnet-4.6");
    assert.ok(entry, "claude-sonnet-4.6 missing from reasoning tier");
    assert.equal(entry.reasoningEffort, "high");
  });

  it("gpt-5 is in reasoning with high reasoning effort", () => {
    const entry = MODEL_CANDIDATES.reasoning.find((m) => m.id === "gpt-5");
    assert.ok(entry, "gpt-5 missing from reasoning tier");
    assert.equal(entry.reasoningEffort, "high");
  });

  it("claude-opus-4.6 is in reasoning with no reasoning effort", () => {
    const entry = MODEL_CANDIDATES.reasoning.find((m) => m.id === "claude-opus-4.6");
    assert.ok(entry, "claude-opus-4.6 missing from reasoning tier");
    assert.equal(entry.reasoningEffort, null);
  });

  // claude-sonnet-4.6 intentionally appears in both builder (medium) and reasoning (high)
  it("claude-sonnet-4.6 appears in builder and reasoning with different efforts", () => {
    const builderEntry = MODEL_CANDIDATES.builder.find((m) => m.id === "claude-sonnet-4.6");
    const reasoningEntry = MODEL_CANDIDATES.reasoning.find((m) => m.id === "claude-sonnet-4.6");
    assert.ok(builderEntry && reasoningEntry, "claude-sonnet-4.6 must appear in both tiers");
    assert.notEqual(
      builderEntry.reasoningEffort,
      reasoningEntry.reasoningEffort,
      "builder and reasoning efforts must differ",
    );
  });
});

// ---------------------------------------------------------------------------
// Keyword list regression
// Guard that critical keywords remain in their respective lists.
// ---------------------------------------------------------------------------
describe("keyword list regression", () => {
  it("EXPLICIT_REVIEW_KEYWORDS includes review, audit, and find bugs", () => {
    assert.ok(EXPLICIT_REVIEW_KEYWORDS.includes("review"), "missing 'review'");
    assert.ok(EXPLICIT_REVIEW_KEYWORDS.includes("audit"), "missing 'audit'");
    assert.ok(EXPLICIT_REVIEW_KEYWORDS.includes("find bugs"), "missing 'find bugs'");
    assert.ok(EXPLICIT_REVIEW_KEYWORDS.includes("regression hunting"), "missing 'regression hunting'");
  });

  it("ORCHESTRATION_KEYWORDS includes all multi-agent and tool-chain patterns", () => {
    assert.ok(ORCHESTRATION_KEYWORDS.includes("parallel agents"), "missing 'parallel agents'");
    assert.ok(ORCHESTRATION_KEYWORDS.includes("multiple agents"), "missing 'multiple agents'");
    assert.ok(ORCHESTRATION_KEYWORDS.includes("multi-agent"), "missing 'multi-agent'");
    assert.ok(ORCHESTRATION_KEYWORDS.includes("tool chain"), "missing 'tool chain'");
    assert.ok(ORCHESTRATION_KEYWORDS.includes("chained tools"), "missing 'chained tools'");
  });

  it("IMPLEMENT_KEYWORDS includes implement, build, refactor, create", () => {
    assert.ok(IMPLEMENT_KEYWORDS.includes("implement"), "missing 'implement'");
    assert.ok(IMPLEMENT_KEYWORDS.includes("build"), "missing 'build'");
    assert.ok(IMPLEMENT_KEYWORDS.includes("refactor"), "missing 'refactor'");
    assert.ok(IMPLEMENT_KEYWORDS.includes("create"), "missing 'create'");
  });

  it("DEBUG_KEYWORDS includes debug, fix, root cause, broken", () => {
    assert.ok(DEBUG_KEYWORDS.includes("debug"), "missing 'debug'");
    assert.ok(DEBUG_KEYWORDS.includes("fix"), "missing 'fix'");
    assert.ok(DEBUG_KEYWORDS.includes("root cause"), "missing 'root cause'");
    assert.ok(DEBUG_KEYWORDS.includes("broken"), "missing 'broken'");
  });

  it("TOOL_KEYWORDS includes bash, curl, api, agent, shell, script", () => {
    for (const kw of ["bash", "curl", "api", "agent", "shell", "script", "command", "invoke"]) {
      assert.ok(TOOL_KEYWORDS.includes(kw), `TOOL_KEYWORDS missing '${kw}'`);
    }
  });
});

// ---------------------------------------------------------------------------
// routing-matrix.md consistency
// Every model ID in policy.mjs must be mentioned in the routing doc so that
// adding or removing a model triggers a visible doc-update requirement.
// ---------------------------------------------------------------------------
describe("routing-matrix.md consistency", () => {
  it("mentions every model ID from MODEL_CANDIDATES", () => {
    const allIds = [
      ...MODEL_CANDIDATES.economy.map((m) => m.id),
      ...MODEL_CANDIDATES.builder.map((m) => m.id),
      ...MODEL_CANDIDATES.reasoning.map((m) => m.id),
    ];
    const missing = [...new Set(allIds)].filter((id) => !MATRIX_CONTENT.includes(id));
    assert.deepEqual(
      missing,
      [],
      `routing-matrix.md is missing these model IDs: ${missing.join(", ")}`,
    );
  });

  it("mentions all ORCHESTRATION_KEYWORDS", () => {
    const missing = ORCHESTRATION_KEYWORDS.filter((kw) => !MATRIX_CONTENT.includes(kw));
    assert.deepEqual(
      missing,
      [],
      `routing-matrix.md missing orchestration keywords: ${missing.join(", ")}`,
    );
  });
});

